class Solution:
    def minimumIndex(self, nums):
        n = len(nums)
        candidate = None
        count = 0
        for x in nums:
            if count == 0:
                candidate = x
                count = 1
            elif x == candidate:
                count += 1
            else:
                count -= 1
        total = nums.count(candidate)
        prefix = 0
        for i in range(n - 1):
            if nums[i] == candidate:
                prefix += 1
            if prefix * 2 > (i + 1) and (total - prefix) * 2 > (n - i - 1):
                return i
        return -1

