var minimumIndex = function(nums) {
    const n = nums.length;
    let candidate = null;
    let count = 0;
    for (const x of nums) {
        if (count === 0) {
            candidate = x;
            count = 1;
        } else if (x === candidate) {
            count++;
        } else {
            count--;
        }
    }
    let total = 0;
    for (const x of nums) if (x === candidate) total++;
    let prefix = 0;
    for (let i = 0; i < n - 1; i++) {
        if (nums[i] === candidate) prefix++;
        if (prefix * 2 > (i + 1) && (total - prefix) * 2 > (n - i - 1)) {
            return i;
        }
    }
    return -1;
};
